import urllib.request
import json

def esql(query):
    payload = json.dumps({"query": query}).encode()
    req = urllib.request.Request(
        "http://elasticsearch:9200/_query?format=json",
        data=payload,
        headers={"Content-Type": "application/json"},
        method="POST"
    )
    with urllib.request.urlopen(req, timeout=30) as resp:
        return json.loads(resp.read())

def to_records(result):
    cols = [c["name"] for c in result["columns"]]
    return [dict(zip(cols, row)) for row in result["values"]]

def pick(rec, *keys):
    return {k: rec.get(k) for k in keys if rec.get(k) is not None}

# ── ERRORS ────────────────────────────────────────────────────────────────────
err_result = esql("""
FROM agent-logs-*
| WHERE level == "ERROR" AND @timestamp > NOW()-12hours
| SORT @timestamp DESC
| LIMIT 100
""")
errors = to_records(err_result)
print(f"=== ERRORS ({len(errors)} found) ===\n")
for r in errors:
    ts = (r.get("@timestamp") or "")[:19]
    print(f"[{ts}] event={r.get('event_type')} | {r.get('message','')[:160]}")
    if r.get("error"):        print(f"  error: {str(r['error'])[:200]}")
    if r.get("exception"):    print(f"  exception: {str(r['exception'])[:200]}")
    if r.get("error_type"):   print(f"  error_type: {r['error_type']}")
    if r.get("tool_name"):    print(f"  tool: {r['tool_name']}")
    print()

# ── WARNINGS ──────────────────────────────────────────────────────────────────
warn_result = esql("""
FROM agent-logs-*
| WHERE level == "WARNING" AND @timestamp > NOW()-12hours
| SORT @timestamp DESC
| LIMIT 100
""")
warnings = to_records(warn_result)
print(f"\n=== WARNINGS ({len(warnings)} found) ===\n")
for r in warnings:
    ts = (r.get("@timestamp") or "")[:19]
    print(f"[{ts}] event={r.get('event_type')} | {r.get('message','')[:160]}")
    if r.get("error"):      print(f"  error: {str(r['error'])[:200]}")
    if r.get("exception"):  print(f"  exception: {str(r['exception'])[:200]}")
    if r.get("tool_name"):  print(f"  tool: {r['tool_name']}")
    print()

